-- ============================================================
-- fn_seed_existing_company.sql
-- One-time seed for companies that existed before 007/008.
-- Inserts all currencies + countries as inactive, then
-- activates base_currency and local_currency from ric_companies.
--
-- USAGE (run in Supabase SQL Editor):
--   SELECT fn_seed_existing_company('your-company-uuid-here');
-- ============================================================

CREATE OR REPLACE FUNCTION fn_seed_existing_company(p_company_id uuid)
RETURNS text AS $$
DECLARE
    v_client_id  uuid;
    v_base       text;
    v_local      text;
    v_name       text;
