    -- Look up the existing company
    SELECT client_id, base_currency, local_currency, company_name
    INTO   v_client_id, v_base, v_local, v_name
    FROM   ric_companies
    WHERE  id = p_company_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Company % not found in ric_companies', p_company_id;
    END IF;

