    RETURN format('Seeded currencies and countries for company "%s" (%s). Base: %s | Local: %s',
                  v_name, p_company_id, COALESCE(v_base, 'not set'), COALESCE(v_local, 'not set'));
END;
$$ LANGUAGE plpgsql;
